@Test
    public void testToMapWithEmptyRecord() throws Exception {
       final CSVParser parser = CSVParser.parse("", CSVFormat.DEFAULT.withHeader("A", "B", "C"));
       final CSVRecord emptyRec = parser.iterator().next();
       final Map<String, String> map = emptyRec.toMap();
       assertTrue(map.isEmpty());
    }

@Test
    public void testToMapWithSingleColumnShort() throws Exception {
       final CSVParser parser = CSVParser.parse("value1", CSVFormat.DEFAULT.withHeader("A", "B"));
       final CSVRecord shortRec = parser.iterator().next();
       final Map<String, String> map = shortRec.toMap();
       assertEquals(1, map.size());
       assertEquals("value1", map.get("A"));
       assertFalse(map.containsKey("B"));
    }

@Test
    public void testToMapWithMultipleColumnsShort() throws Exception {
       final CSVParser parser = CSVParser.parse("v1,v2", CSVFormat.DEFAULT.withHeader("A", "B", "C", "D"));
       final CSVRecord shortRec = parser.iterator().next();
       final Map<String, String> map = shortRec.toMap();
       assertEquals(2, map.size());
       assertEquals("v1", map.get("A"));
       assertEquals("v2", map.get("B"));
       assertFalse(map.containsKey("C"));
       assertFalse(map.containsKey("D"));
    }
